queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?format_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFormats ?child ; p:hasAdvertisements ?parent . } GROUP BY ?child }
  ?child p:format_name ?format_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Advertisements } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?title ?format_name WHERE {
  ?advertisements_formats a :Advertisements_Formats .
  ?formats a :Formats .
  ?advertisements_formats p:hasFormats ?formats .
  ?advertisements a :Advertisements .
  ?advertisements_formats p:hasAdvertisements ?advertisements .
  ?advertisements p:title ?title .
  ?formats p:format_name ?format_name .
} }
  collective: { SELECT ?format_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFormats ?child ; p:hasAdvertisements ?parent . } GROUP BY ?child }
  ?child p:format_name ?format_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Advertisements } }
  FILTER(?nf = ?total)
} }
}
